#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeProviiWallet: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = ProviiWallet

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> ProviiWallet {
        return ProviiWallet(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: ProviiWallet) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ProviiWallet {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

